import time, random, urllib.request, json

def get_token_with_retry(resource: str, max_retries: int = 5) -> str:
    url = (
        'http://169.254.169.254/metadata/identity/oauth2/token'
        f'?api-version=2018-02-01&resource={resource}'
    )
    req = urllib.request.Request(url, headers={'Metadata': 'true'})

    for attempt in range(max_retries):
        try:
            with urllib.request.urlopen(req, timeout=5) as resp:
                data = json.loads(resp.read())
                return data['access_token']
        except Exception as e:
            if attempt == max_retries - 1:
                raise
            wait = (2 ** attempt) + random.uniform(0, 1)
            time.sleep(wait)

    raise RuntimeError('Token acquisition failed after retries')

import azure.functions as func
from azure.identity import DefaultAzureCredential
from azure.keyvault.secrets import SecretClient
import logging

# Initialize outside the handler — credential cached across warm invocations
_credential = DefaultAzureCredential()
_kv_client  = SecretClient('https://my-vault.vault.azure.net', _credential)

app = func.FunctionApp(http_auth_level=func.AuthLevel.ANONYMOUS)

@app.route(route='config')
def get_config(req: func.HttpRequest) -> func.HttpResponse:
    try:
        secret = _kv_client.get_secret('app-config')
        return func.HttpResponse(secret.value, status_code=200)
    except Exception as e:
        logging.error('Key Vault error: %s', e)
        return func.HttpResponse('Unavailable', status_code=503)

using Azure.Identity;
using Azure.Security.KeyVault.Secrets;
using Microsoft.Azure.Functions.Worker;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;

// Register credential as singleton in Program.cs
var host = new HostBuilder()
    .ConfigureFunctionsWorkerDefaults()
    .ConfigureServices(s =>
    {
        s.AddSingleton<TokenCredential>(new DefaultAzureCredential());
        s.AddSingleton(sp =>
            new SecretClient(
                new Uri("https://my-vault.vault.azure.net"),
                sp.GetRequiredService<TokenCredential>()));
    })
    .Build();

// Function handler
public class ConfigFunction
{
    private readonly SecretClient _kv;
    public ConfigFunction(SecretClient kv) => _kv = kv;

    [Function("GetConfig")]
    public async Task<HttpResponseData> Run([HttpTrigger(...)] HttpRequestData req)
    {
        var secret = await _kv.GetSecretAsync("app-config");
        var resp = req.CreateResponse(HttpStatusCode.OK);
        await resp.WriteStringAsync(secret.Value.Value);
        return resp;
    }
}
